   178â†’	// collect deletes from this level; build first to check lower level overlapped puts
   179â†’	for _, req := range reqs {
   180â†’		tv, ok := req.Request.(*pb.RequestOp_RequestDeleteRange)
   181â†’		if !ok {
   182â†’			continue
   183â†’		}
   184â†’		dreq := tv.RequestDeleteRange
   185â†’		if dreq == nil {
   186â†’			continue
   187â†’		}
   188â†’		var iv adt.Interval
   189â†’		if len(dreq.RangeEnd) != 0 {
   190â†’			iv = adt.NewStringAffineInterval(string(dreq.Key), string(dreq.RangeEnd))
   191â†’		} else {
   192â†’			iv = adt.NewStringAffinePoint(string(dreq.Key))
   193â†’		}
   194â†’		dels.Insert(iv, struct{}{})
   195â†’	}
   196â†’
   197â†’	// collect children puts/deletes
   198â†’	puts := make(map[string]struct{})
   199â†’	for _, req := range reqs {
   200â†’		tv, ok := req.Request.(*pb.RequestOp_RequestTxn)
   201â†’		if !ok {
   202â†’			continue
   203â†’		}
   204â†’		putsThen, delsThen, err := checkIntervals(tv.RequestTxn.Success)
   205â†’		if err != nil {
   206â†’			return nil, dels, err
   207â†’		}
   208â†’		putsElse, delsElse, err := checkIntervals(tv.RequestTxn.Failure)
   209â†’		if err != nil {
   210â†’			return nil, dels, err
   211â†’		}
   212â†’		for k := range putsThen {
   213â†’			if _, ok := puts[k]; ok {
   214â†’				return nil, dels, rpctypes.ErrGRPCDuplicateKey
   215â†’			}
   216â†’			if dels.Intersects(adt.NewStringAffinePoint(k)) {
   217â†’				return nil, dels, rpctypes.ErrGRPCDuplicateKey
   218â†’			}
   219â†’			puts[k] = struct{}{}
   220â†’		}
   221â†’		for k := range putsElse {
   222â†’			if _, ok := puts[k]; ok {
   223â†’				// if key is from putsThen, overlap is OK since
   224â†’				// either then/else are mutually exclusive
   225â†’				if _, isSafe := putsThen[k]; !isSafe {
   226â†’					return nil, dels, rpctypes.ErrGRPCDuplicateKey
   227â†’				}
   228â†’			}
   229â†’			if dels.Intersects(adt.NewStringAffinePoint(k)) {
   230â†’				return nil, dels, rpctypes.ErrGRPCDuplicateKey
   231â†’			}
   232â†’			puts[k] = struct{}{}
   233â†’		}
   234â†’		dels.Union(delsThen, adt.NewStringAffineInterval("\x00", ""))
   235â†’		dels.Union(delsElse, adt.NewStringAffineInterval("\x00", ""))
   236â†’	}
   237â†’
   238â†’	// collect and check this level's puts
   239â†’	for _, req := range reqs {
   240â†’		tv, ok := req.Request.(*pb.RequestOp_RequestPut)
   241â†’		if !ok || tv.RequestPut == nil {
   242â†’			continue
   243â†’		}
   244â†’		k := string(tv.RequestPut.Key)
   245â†’		if _, ok := puts[k]; ok {
   246â†’			return nil, dels, rpctypes.ErrGRPCDuplicateKey
   247â†’		}
   248â†’		if dels.Intersects(adt.NewStringAffinePoint(k)) {
   249â†’			return nil, dels, rpctypes.ErrGRPCDuplicateKey
   250â†’		}
   251â†’		puts[k] = struct{}{}
   252â†’	}
   253â†’	return puts, dels, nil
   254â†’}
