   256â†’func checkRequestOp(u *pb.RequestOp, maxTxnOps int) error {
   257â†’	// TODO: ensure only one of the field is set.
   258â†’	switch uv := u.Request.(type) {
   259â†’	case *pb.RequestOp_RequestRange:
   260â†’		return checkRangeRequest(uv.RequestRange)
   261â†’	case *pb.RequestOp_RequestPut:
   262â†’		return checkPutRequest(uv.RequestPut)
   263â†’	case *pb.RequestOp_RequestDeleteRange:
   264â†’		return checkDeleteRequest(uv.RequestDeleteRange)
   265â†’	case *pb.RequestOp_RequestTxn:
   266â†’		return checkTxnRequest(uv.RequestTxn, maxTxnOps)
   267â†’	default:
   268â†’		// empty op / nil entry
   269â†’		return rpctypes.ErrGRPCKeyNotFound
   270â†’	}
   271â†’}
